.darma-loader-uiverse-molten-blob-core {
  --c1: var(--loader-color, #ffbf48);
  --c2: var(--loader-secondary-color, #be4a1d);
  --t: 2s;
  --size: 1;
  position: relative;
  width: 100px;
  height: 100px;
  border-radius: 50%;
  transform: scale(var(--size));
  box-shadow:
    0 0 25px 0 #ffbf4780,
    0 20px 50px 0 #bf4a1d80;
  animation: darma-loader-uiverse-molten-blob-core-colorize calc(var(--t) * 3) ease-in-out infinite;
  overflow: hidden;
}

.darma-loader-uiverse-molten-blob-core::before {
content: "";
position: absolute;
inset: 0;
border-radius: 50%;
border-top: 1px solid var(--c1);
border-bottom: 1px solid var(--c2);
background: linear-gradient(180deg, #ffbf4740, #bf4a1d80);
box-shadow:
inset 0 10px 10px 0 #ffbf4780,
inset 0 -10px 10px 0 #bf4a1d80;
}

.darma-loader-uiverse-molten-blob-core__inner {
position: absolute;
inset: 0;
border-radius: 50%;
overflow: hidden;
filter: blur(0.2px) contrast(1.45);
}

.darma-loader-uiverse-molten-blob-core__blob {
position: absolute;
border-radius: 42%;
background: linear-gradient(180deg, var(--c1) 30%, var(--c2) 70%);
}

.darma-loader-uiverse-molten-blob-core__b1 {
width: 44px;
height: 44px;
top: 12px;
left: 28px;
transform-origin: 50% 130%;
animation: darma-loader-uiverse-molten-blob-core-spin var(--t) linear infinite reverse;
}

.darma-loader-uiverse-molten-blob-core__b2 {
width: 40px;
height: 40px;
top: 18px;
left: 30px;
transform-origin: 50% -30%;
animation: darma-loader-uiverse-molten-blob-core-spin var(--t) linear infinite;
animation-delay: calc(var(--t) / -3);
}

.darma-loader-uiverse-molten-blob-core__b3 {
width: 30px;
height: 30px;
top: 28px;
left: 35px;
transform-origin: -30% -10%;
animation: darma-loader-uiverse-molten-blob-core-spin var(--t) linear infinite reverse;
}

.darma-loader-uiverse-molten-blob-core__b4 {
width: 28px;
height: 28px;
top: 30px;
left: 36px;
transform-origin: -30% -10%;
animation: darma-loader-uiverse-molten-blob-core-spin var(--t) linear infinite reverse;
animation-delay: calc(var(--t) / -2);
}

.darma-loader-uiverse-molten-blob-core__b5 {
width: 30px;
height: 30px;
top: 28px;
left: 35px;
transform-origin: 130% -10%;
animation: darma-loader-uiverse-molten-blob-core-spin var(--t) linear infinite;
}

.darma-loader-uiverse-molten-blob-core__b6 {
width: 28px;
height: 28px;
top: 30px;
left: 36px;
transform-origin: 130% -10%;
animation: darma-loader-uiverse-molten-blob-core-spin var(--t) linear infinite;
animation-delay: calc(var(--t) / -1.5);
}

@keyframes darma-loader-uiverse-molten-blob-core-spin {
to {
transform: rotate(360deg);
}
}

@keyframes darma-loader-uiverse-molten-blob-core-colorize {
0% {
filter: hue-rotate(0deg);
}
20% {
filter: hue-rotate(-30deg);
}
40% {
filter: hue-rotate(-60deg);
}
60% {
filter: hue-rotate(-90deg);
}
80% {
filter: hue-rotate(-45deg);
}
100% {
filter: hue-rotate(0deg);
}
}

